from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

# Configure Redis connection
# In a production environment, use environment variables or a dedicated config manager
REDIS_HOST = 'localhost'
REDIS_PORT = 6379
REDIS_DB = 0

redis_client = redis.Redis(host=REDIS_HOST, port=REDIS_PORT, db=REDIS_DB, decode_responses=True)

@app.route('/redis-command', methods=['GET'])
def execute_redis_command_api():
    """
    Executes a Redis command provided in the 'command' URL parameter.
    Example: GET /redis-command?command=GET%20mykey
    Example: GET /redis-command?command=SET%20mykey%20myvalue%20EX%2060
    """
    command_str = request.args.get('command')

    if not command_str:
        return jsonify({
            "status": "error",
            "message": "Missing 'command' parameter. Please provide a Redis command."
        }), 400

    try:
        # Split the command string into parts.
        # This handles commands with arguments (e.g., "GET mykey" -> ["GET", "mykey"])
        command_parts = command_str.split()

        if not command_parts:
            return jsonify({
                "status": "error",
                "message": "Empty command string provided."
            }), 400

        # Execute the Redis command.
        # The *command_parts unpacks the list into positional arguments for execute_command.
        # E.g., ['GET', 'mykey'] becomes redis_client.execute_command('GET', 'mykey')
        result = redis_client.execute_command(*command_parts)

        return jsonify({
            "status": "success",
            "command": command_str,
            "result": result
        })

    except redis.exceptions.RedisError as e:
        # Catch specific Redis errors (e.g., unknown command, wrong number of arguments)
        return jsonify({
            "status": "error",
            "command": command_str,
            "message": str(e)
        }), 500
    except Exception as e:
        # Catch any other unexpected errors
        return jsonify({
            "status": "error",
            "command": command_str,
            "message": f"An unexpected server error occurred: {str(e)}"
        }), 500

